if command == "add":
    if len(sys.argv) < 3:
        return
    content = sys.argv[2]
    todos = load_todos()
    todos.append(content)
    save_todos(todos)

elif command == "list":
    todos = load_todos()
    for i, todo in enumerate(todos, 1):
        print(f"{i}: {todo}")

elif command == "remove":
    if len(sys.argv) < 3:
        return
    try:
        task_id = int(sys.argv[2])
    except ValueError:
        return
    todos = load_todos()
    if 1 <= task_id <= len(todos):
        todos.pop(task_id - 1)
        save_todos(todos)

